SELECT hot_table_raw_id, schema_name, table_name, table_size, seq_scan, seq_tup_read, idx_scan, idx_tup_fetch, n_tup_ins, n_tup_upd, n_tup_del, n_tup_hot_upd, n_live_tup, n_dead_tup, bloat_percent, last_vacuum, last_autovacuum, heap_blks_read, heap_blks_hit, CASE WHEN bloat_percent >= 30 THEN '위험' WHEN bloat_percent >= 15 THEN '주의' ELSE '정상' END as status FROM hot_table_raw WHERE database_id = #{databaseId} AND collected_at BETWEEN #{startTime} AND #{endTime}
AND CASE WHEN bloat_percent >= 30 THEN '위험' WHEN bloat_percent >= 15 THEN '주의' ELSE '정상' END IN
#{status}
ORDER BY collected_at DESC, table_size DESC
